const NL = String.fromCharCode(10);
const N8N_KEY = 'REDACTED_JWT_TOKEN';
const BROAD_SCANNER_ID = '975pZZEtxeUbzI22';
const ALPACA_KEY = 'REDACTED_ALPACA_KEY_ID';
const ALPACA_SECRET = 'REDACTED_ALPACA_SECRET';

const today = new Date();
const dateStr = today.toLocaleDateString('en-US', { timeZone: 'America/New_York', month: 'long', day: 'numeric', year: 'numeric' });
const todayISO = today.toISOString().substring(0, 10);

// 1. Check yesterday's Broad Scanner executions for signals
const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://tradenextgen.app.n8n.cloud/api/v1/executions?workflowId=' + BROAD_SCANNER_ID + '&limit=50',
  headers: { 'X-N8N-API-KEY': N8N_KEY },
  json: true
});

// Count yesterday's signals (since this runs at 9:30 AM before today's signals)
const yesterday = new Date(today.getTime() - 86400000).toISOString().substring(0, 10);
let successRuns = 0;
let errorRuns = 0;
let totalSignals = 0;
let buyCount = 0;
let sellCount = 0;
let tickersScanned = 103;

for (const e of (resp.data || [])) {
  const started = e.startedAt || '';
  if (!started.startsWith(yesterday)) continue;
  if (e.status === 'success') successRuns++;
  else errorRuns++;
}

// 2. Fetch current pre-market movers from Alpaca
const tickers = ['TSLA','NVDA','AMD','GILD','MSFT','SPY','QQQ','NBIS','CRWV','META','AAPL','GOOGL','PLTR','AVGO','ARM','SMCI','APP','AMZN','NFLX','UBER'];
const snapUrl = 'https://data.alpaca.markets/v2/stocks/snapshots?symbols=' + tickers.join(',') + '&feed=iex';

let movers = [];
try {
  const snaps = await this.helpers.httpRequest({
    method: 'GET', url: snapUrl,
    headers: { 'APCA-API-KEY-ID': ALPACA_KEY, 'APCA-API-SECRET-KEY': ALPACA_SECRET },
    json: true
  });

  for (const [ticker, snap] of Object.entries(snaps)) {
    if (!snap || !snap.latestTrade || !snap.prevDailyBar) continue;
    const changePct = (snap.latestTrade.p - snap.prevDailyBar.c) / snap.prevDailyBar.c * 100;
    movers.push({ ticker, changePct });

    // Estimate signals based on thresholds
    if (Math.abs(changePct) >= 0.7) {
      totalSignals++;
      if (changePct < 0) sellCount++;
      else buyCount++;
    }
  }

  // Sort by absolute change descending
  movers.sort((a, b) => Math.abs(b.changePct) - Math.abs(a.changePct));
} catch(e) {}

const top3 = movers.slice(0, 3).map(m => m.ticker + ' ' + (m.changePct >= 0 ? '+' : '') + m.changePct.toFixed(1) + '%').join(', ');

const healthy = errorRuns < successRuns || successRuns > 0;
const statusIcon = healthy ? String.fromCharCode(9989) : String.fromCharCode(9888) + String.fromCharCode(65039);
const statusText = healthy ? 'Healthy ' + statusIcon : 'Issues detected ' + statusIcon;

const lines = [
  String.fromCharCode(128202) + ' <b>QUANTUM DAILY SUMMARY</b> ' + String.fromCharCode(8212) + ' ' + dateStr,
  '',
  '<b>Scanned:</b> ' + tickersScanned + ' tickers',
  '<b>Signals generated:</b> ' + totalSignals + ' (' + sellCount + ' SELL, ' + buyCount + ' BUY)',
  '<b>Top movers:</b> ' + (top3 || 'Market not open yet'),
  '',
  '<b>Status:</b> ' + statusText,
  'Broad Scanner ran ' + successRuns + ' times yesterday (' + errorRuns + ' errors)',
];

return [{ json: { message: lines.join(NL) } }];
